INSERT INTO `i18n_message` ( `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES ( 'BACK_END', 'BIZ_MEMBER_WELCOME_CONTENT_8100', 'ko-KR', '%s님, %s정식 회원이 되신 것을 축하합니다. %s을(를) 선택한 순간부터 회원님의 계정과 자산은 안전하게 보호됩니다. 저희는 전 세계 최고의 스포츠 경기, 라이브 카지노, 보드게임, 슬롯 게임 등 다양한 콘텐츠를 제공해 드리며, 간편한 예금 방식과 빠른 출금 시스템으로 언제나 안심하고 이용하실 수 있습니다.', 20241123065529, NULL, NULL, NULL);
