INSERT INTO `i18n_message` ( `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES ( 'BACK_END', 'BIZ_MEMBER_SECURITY_CONTENT_8100', 'ko-KR', '회원님의 계정 보안을 위해 충전/출금 관련 문의는 반드시 공식 고객센터를 통해 진행해 주세요. 사적인 거래는 절대 하지 마세요! 문의사항이 있으시면 7*24시간 고객센터에 문의해 주세요~', 20241123065529, NULL, NULL, NULL);
