INSERT INTO `i18n_message` ( `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES ( 'BACK_END', 'BIZ_MEMBER_FUNDS_SECURITY_TITLE_8100', 'ko-KR', '자금 안전 알림', 20241123065529, NULL, NULL, NULL);
