INSERT INTO `i18n_message` ( `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES ('BACK_END', 'BIZ_MEMBER_FUNDS_SECURITY_CONTENT_8100', 'ko-KR', '회원님의 자금 안전을 위해 %s를 사칭한 자의 안내에 절대 응하지 마세요. 실제 입금 확인 없이 확인 을 유도하거나, 계정 비밀번호를 요구하거나, 계정을 임대하거나 판매하는 행위는 모두 위험합니다. %s 플랫폼은 절대로 이메일 등을 통해 이체를 요청하지 않습니다! 해당 행위는 해킹 시도이며, 계정 정보가 변경되어 자산 손실로 이어질 수 있습니다. 제보는 피드백 버튼을 통해 접수해 주시면 보상 혜택이 있습니다. 문의 사항은 7*24시간 고객센터로 연락해 주세요.', 20241123065529, NULL, NULL, NULL);
