INSERT INTO `i18n_message` ( `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES ('BACK_END', 'BIZ_MEMBER_VERSION_UPGRADE_CONTENT_8100', 'ko-KR', '더 나은 이용을 위해 새로운 버전이 업데이트되었습니다. 지금 바로 최신 버전으로 업데이트해 주세요!', 20241123065529, NULL, NULL, NULL);



