INSERT INTO `i18n_message` ( `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES ( 'BACK_END', 'BIZ_AGENT_WELCOME_CONTENT_8100', 'ko-KR', '%s님, %s의 제휴 파트너가 되신 것을 진심으로 환영합니다! 최고의 리소스를 누구보다 먼저 확보하고 싶으신가요? 오직 파트너님만을 위한 프리미엄 맞춤 서비스를 원하시나요? 최신 최상급 지원 혜택이 궁금하신가요? 지금 바로 7*24시간 제휴 전담 온라인 고객센터에 문의해 주세요. 저희는 가장 신뢰할 수 있는 지원을 약속드립니다!', 20241123065529, NULL, NULL, NULL);
